#nullable enable // autogenerated

using MVZ2.GameContent.Damages;
using MVZ2.GameContent.Entities;
using MVZ2.Vanilla.Entities;

using PVZEngine.Callbacks;
using PVZEngine.Definitions;
using PVZEngine.Entities;

namespace MVZ2.GameContent.Contraptions
{
    [AutoEntityBehaviourDefinition(VanillaEntityBehaviourNames.ExplodeOnRadiationDeath)]
    public class ExplodeOnRadiationDeathBehaviour : AIEntityBehaviour
    {
        public ExplodeOnRadiationDeathBehaviour(string nsp, string name) : base(nsp, name)
        {
            AddTrigger(LevelCallbacks.POST_ENTITY_DEATH, PostEntityDeathCallback, filter: EntityTypes.PLANT);
        }
        private void PostEntityDeathCallback(LevelCallbacks.EntityDeathParams param, CallbackResult result)
        {
            var entity = param.entity;
            var info = param.deathInfo;
            if (!entity.Definition.HasBehaviour(this))
                return;
            if (!info.HasEffect(VanillaDamageEffects.RADIATION))
                return;
            var range = entity.GetRange();
            var damage = entity.GetDamage();
            entity.BehaviourExplode(range, damage);
            entity.Remove();
        }
    }
}
